<div class=\"container mt-4\">
    <h1>Modifier mon Profil</h1>

    <div class=\"card\">
        <div class=\"card-body\">
            {{ form_start(form) }}
            
            <div class=\"row\">
                <div class=\"col-md-6\">
                    {{ form_row(form.nomMembre) }}
                    {{ form_row(form.prenomMembre) }}
                    {{ form_row(form.mailMembre) }}
                    {{ form_row(form.telMembre) }}
                </div>
                <div class=\"col-md-6\">
                    {{ form_row(form.rueMembre) }}
                    {{ form_row(form.cpMembre) }}
                    {{ form_row(form.villeMembre) }}
                </div>
            </div>

            <div class=\"form-group\">
                <button type=\"submit\" class=\"btn btn-success\">
                    <i class=\"fas fa-save\"></i> Enregistrer les modifications
                </button>
                <a href=\"{{ path('app_profile_show') }}\" class=\"btn btn-secondary\">
                    <i class=\"fas fa-times\"></i> Annuler
                </a>
            </div>

            {{ form_end(form) }}
        </div>
    </div>
</div>
{% endblock %}", "profile/edit.html.twig", "/var/www/html/AP/Agora/templates/profile/edit.html.twig");
